    vatLawRows: [['— EXEMPTÉ (chap. 3) —','Hors du champ de la loi, pas de droit à déduction'],['Services de santé (§ 3-2)','Exempté','Médecin, dentiste, kinésithérapeute etc. — pas de TVA et pas de droit à déduction'],['Services sociaux (§ 3-4)','Exempté','Protection de l\'enfance, soins aux personnes âgées, traitement des addictions etc.'],['Enseignement (§ 3-5)','Exempté','Écoles, cours, formation — tant public que privé'],['Services financiers (§ 3-6)','Exempté','Banque, assurance, négoce de valeurs mobilières — pas de TVA'],['Art/culture — représentation (§ 3-7)','Exempté','Concert, théâtre, danse — les billets sont sans TVA'],['Sport — droit de pratiquer (§ 3-8)','Exempté','Salle de sport, terrain de football, piscine etc.'],['Exercice de l\'autorité publique (§ 3-9)','Exempté'],['Bien immobilier/location (§ 3-11)','Exempté (exception au (2))','La location de logements et de locaux commerciaux est exemptée — mais l\'enregistrement volontaire est possible pour les activités'],['Organisations caritatives (§ 3-12)','Exempté (certaines ventes)','Marchés aux puces, bazars etc. d\'organisations caritatives'],['Organisations à but non lucratif — cotisations (§ 3-13)','Exempté'],['Jeux d\'argent (§ 3-14)','Exempté'],['Funérailles — cérémonie (§ 3-15)','Exempté'],['Jetons de présence (§ 3-17)','Exempté (avec cotisation employeur)','Les jetons de présence sont exemptés de TVA mais la cotisation employeur doit être payée'],['Biens usagés privés (§ 3-19)','Exempté','Les particuliers vendant des biens usagés n\'ont pas besoin de facturer la TVA'],['— EXONÉRÉ (chap. 6) —','Soumis à la loi, 0% de TVA collectée, droit à déduction'],['Journaux (§ 6-1)','Exonéré'],['Périodiques (§ 6-3)','Exonéré (dernier alinéa)'],['Livres (§ 6-4)','Exonéré (dernier alinéa)'],['Électricité ménages Nord-Norvège (§ 6-6)','Exonéré'],['Voiture électrique ≤300 000 kr (§ 6-8)','Exonéré','S\'applique uniquement au montant d\'achat jusqu\'à 300 000 kr — au-delà, 25% de TVA est facturé'],['Navires ≥15m (§ 6-9)','Exonéré'],['Aéronefs professionnels (§ 6-10)','Exonéré'],['Cession d\'entreprise (§ 6-14)','Exonéré','Lorsqu\'une entreprise entière est vendue globalement, l\'historique TVA est transféré — pas de TVA sur la vente'],['Exportation de biens (§ 6-21)','Exonéré','Exportation à l\'étranger — 0% de TVA mais plein droit à déduction de la TVA d\'amont'],['Exportation de services (§ 6-22)','Exonéré'],['Transport vers/depuis l\'étranger (§ 6-28)','Exonéré'],['— PRÉLÈVEMENT (chap. 3 partie II) —',''],['Prélèvement de biens (§ 3-21)','Soumis à la TVA','Si vous prenez des marchandises de l\'entreprise pour un usage personnel, vous devez facturer la TVA'],['Prélèvement de services privés (§ 3-22)','Soumis à la TVA'],['Nourriture/produits naturels/repr. (§ 3-23)','Soumis à la TVA'],['— IMPORTATION (chap. 3 partie III) —',''],['Biens importés (§ 3-29)','Soumis à la TVA','Importation de biens — la TVA est calculée lors du dédouanement'],['Services à distance (§ 3-30)','Autoliquidation','Si vous achetez des services numériques de l\'étranger, vous calculez la TVA vous-même']],
    vatDefRows: [['Chiffre d\'affaires (a)','Livraison de biens/services contre rémunération','Si vous échangez quelque chose contre de l\'argent, c\'est du chiffre d\'affaires'],['Biens (b)','Objets physiques, biens immobiliers, électricité, eau, gaz, chaleur, froid'],['Services (c)','Tout ce qui peut être commercialisé et n\'est pas un bien','Conseil, coiffeur, transport, réparation etc.'],['Assujetti (d)','Enregistré/tenu de s\'enregistrer au registre de la TVA','Entreprises avec un chiffre d\'affaires supérieur à 50 000 kr sur 12 mois'],['TVA collectée (e)','Calculée et payée lors du chiffre d\'affaires et des prélèvements','La TVA que vous ajoutez au prix et collectez auprès du client'],['TVA déductible (f)','Supportée lors d\'un achat ou d\'une importation','La TVA que vous payez lorsque vous achetez des biens/services pour l\'entreprise'],['Exemption de la loi (g)','Chiffre d\'affaires non couvert par la loi → pas de droit à déduction','L\'entreprise ne peut pas déduire la TVA sur les achats liés au chiffre d\'affaires exempté'],['Exonération de TVA (h)','Couvert par la loi, mais 0% de TVA collectée → plein droit à déduction','L\'exportation est exonérée — vous ne facturez pas de TVA, mais pouvez déduire la TVA d\'amont'],['Services à distance (i)','Non liés à un lieu physique précis','Services informatiques, conseil en ligne, streaming etc.'],['Services électroniques (j)','À distance, fournis par internet, automatisés','Applications, e-books, services de streaming, cours en ligne']],
    vatDedRows: [['Règle principale (§ 8-1)','Déduction de la TVA d\'amont pour usage dans l\'activité enregistrée','Vous récupérez la TVA sur tout ce que vous achetez pour l\'entreprise'],['Usage mixte (§ 8-2)','Déduction proportionnelle selon l\'usage estimé','Si quelque chose est utilisé à 60% pour l\'entreprise et 40% privé, vous obtenez 60% de déduction'],['Pas de déduction : restauration (§ 8-3 a)','','Nourriture et boissons pour les employés, clients etc.'],['Pas de déduction : représentation (§ 8-3 e)','','Dîners avec les clients, événements pour les relations d\'affaires'],['Pas de déduction : cadeaux (§ 8-3 f)','Pas de valeur négligeable','Les cadeaux au-dessus du seuil négligeable ne donnent pas droit à déduction'],['Pas de déduction : logement/bien-être (§ 8-3 g)','Exception : cantines d\'entreprise'],['Véhicule de tourisme (§ 8-4)','Pas de déduction (exception : location, taxi, vente)','Une voiture de fonction ne donne pas droit à déduction de TVA sauf si utilisée pour la location ou le transport de personnes'],['Paiement par banque (§ 8-8)','Obligatoire à partir de ≥10 000 kr','Les paiements en espèces supérieurs à 10 000 kr ne donnent pas droit à déduction de TVA']],
    vatAdjRows: [['Bien d\'investissement mobilier (§ 9-1 a)','TVA d\'amont ≥50 000 kr','Machines, véhicules etc. avec TVA supérieure à 50 000 kr'],['Bien d\'investissement immobilier (§ 9-1 b)','TVA d\'amont ≥100 000 kr','Bâtiments, installations etc. avec TVA supérieure à 100 000 kr'],['Période d\'ajustement mobilier (§ 9-4)','5 ans','Si vous changez l\'usage dans les 5 prochaines années, la déduction de TVA doit être ajustée'],['Période d\'ajustement immobilier (§ 9-4)','10 ans','Si vous changez l\'usage dans les 10 prochaines années, la déduction de TVA doit être ajustée']],
    vatCalcRows: [['Règle principale (§ 4-1)','La contrepartie hors TVA'],['Échange en nature (§ 4-3)','Valeur de marché courante','En cas d\'échange, le prix du marché est utilisé comme base pour la TVA'],['Communauté d\'intérêts (§ 4-4)','Pas inférieur à la valeur de marché courante','Si vous vendez à bas prix à votre propre société, la TVA est calculée sur le prix du marché'],['Perte sur créance (§ 4-7)','Possibilité de corriger une créance définitivement perdue','Le client ne paie jamais — vous pouvez alors récupérer la TVA que vous avez versée']],
    vatRegRows: [['Enregistrement commun (§ 2-2)','≥85% de propriété, responsabilité solidaire','Les sociétés d\'un groupe peuvent être enregistrées comme une seule unité TVA'],['Enregistrement volontaire location (§ 2-3)','Bâtiments/installations pour locataire enregistré TVA','Le bailleur obtient la déduction de TVA sur les travaux/construction lorsque le locataire est enregistré à la TVA'],['Pré-enregistrement (§ 2-4)','Acquisitions importantes avant le chiffre d\'affaires','Une entreprise nouvellement créée peut s\'enregistrer avant d\'avoir atteint 50 000 kr de chiffre d\'affaires']],
